# Python 3.11+
"""Domain entities, enums and errors for the movie ticket booking system.

These are the "nouns". The one with real behaviour is Seat, which is a tiny
STATE MACHINE — it is the single place allowed to change a seat's status, so the
service can never flip a seat illegally.
"""

from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum

# Fixed seat layout for every screen: rows A..Z, columns 0..20.
ROWS: list[str] = [chr(c) for c in range(ord("A"), ord("Z") + 1)]
COLS: range = range(0, 21)


# ── ENUMS ─────────────────────────────────────────────────────────────────────
class SeatStatus(Enum):
    AVAILABLE = "AVAILABLE"
    BOOKED = "BOOKED"


class ReservationStatus(Enum):
    CONFIRMED = "CONFIRMED"
    CANCELLED = "CANCELLED"


# ── ERRORS ────────────────────────────────────────────────────────────────────
# One base so callers can catch the whole family; specific types so a test (or a
# UI) can tell "no such showtime" apart from "seat already booked".
class BookingError(Exception):
    pass


class MovieNotFoundError(BookingError):
    pass


class ShowtimeNotFoundError(BookingError):
    pass


class SeatNotFoundError(BookingError):
    pass


class SeatAlreadyBookedError(BookingError):
    pass


class EmptySeatSelectionError(BookingError):
    pass


class InvalidReservationError(BookingError):
    pass


# ── ENTITIES ──────────────────────────────────────────────────────────────────
@dataclass(frozen=True)
class Movie:
    # Frozen: a movie's identity never changes once catalogued.
    id: str
    title: str


@dataclass
class Seat:
    """A single seat as a STATE MACHINE: AVAILABLE -> BOOKED -> AVAILABLE.

    Only this class mutates its own status, so the service can never skip a step
    or corrupt a seat from the outside.
    """
    row: str
    col: int
    status: SeatStatus = SeatStatus.AVAILABLE

    @property
    def id(self) -> str:
        return f"{self.row}{self.col}"

    def is_available(self) -> bool:
        return self.status == SeatStatus.AVAILABLE

    def book(self) -> None:
        # Guard the from-state so an already-booked seat can never be double-booked.
        if self.status != SeatStatus.AVAILABLE:
            raise SeatAlreadyBookedError(f"seat {self.id} is already booked")
        self.status = SeatStatus.BOOKED

    def release(self) -> None:
        # Safe to call twice: if the seat is already free this is a no-op, so a
        # cancel can never under-flow the state.
        self.status = SeatStatus.AVAILABLE


@dataclass(frozen=True)
class Screen:
    # A physical screen. Its seat layout is fixed and built per showtime, so the
    # screen itself only needs identity.
    id: str
    name: str


@dataclass(frozen=True)
class Theater:
    id: str
    name: str
    screen_ids: tuple[str, ...] = ()


@dataclass
class Showtime:
    """One screening of a movie on a screen at a time. OWNS its seat map and is
    the unit of locking — all booking for one showtime serialises on this object.
    """
    id: str
    movie_id: str
    screen_id: str
    start_time: datetime
    seats: dict[str, Seat] = field(default_factory=dict)

    def seat(self, seat_id: str) -> Seat:
        s = self.seats.get(seat_id)
        if s is None:
            raise SeatNotFoundError(f"seat {seat_id} is not on showtime {self.id}")
        return s

    def available_seats(self) -> list[Seat]:
        return [s for s in self.seats.values() if s.is_available()]


@dataclass
class Reservation:
    # The glue object: ties a confirmation id to the showtime and the exact seats
    # it holds, so a cancel can free precisely those seats.
    confirmation_id: str
    showtime_id: str
    seat_ids: tuple[str, ...]
    status: ReservationStatus = ReservationStatus.CONFIRMED


def build_seat_map() -> dict[str, Seat]:
    """The standard layout every screen uses: rows A..Z x cols 0..20 = 546 seats."""
    return {f"{r}{c}": Seat(row=r, col=c) for r in ROWS for c in COLS}
